import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetter() {
  const { applicationId } = useParams();
  const navigate = useNavigate();

  const [application, setApplication] = useState(null);

  /* =========================
     OFFER FORM FIELDS
  ========================= */
  const [salary, setSalary] = useState("");
  const [joiningDate, setJoiningDate] = useState("");
  const [location, setLocation] = useState("");
  const [notes, setNotes] = useState("");

  /* =========================
     LOAD APPLICATION
  ========================= */
  useEffect(() => {
    const applications =
      JSON.parse(localStorage.getItem("applications")) || [];

    const found = applications.find(
      (a) => String(a.id) === String(applicationId)
    );

    setApplication(found);
  }, [applicationId]);

  /* =========================
     SAVE OFFER LETTER
  ========================= */
  const handleSaveOffer = () => {
    if (!salary || !joiningDate || !location) {
      alert("Please fill all required fields");
      return;
    }

    /* ---------- SAVE OFFER ---------- */
    const existingOffers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const newOffer = {
      applicationId,
      email: application.email,
      jobTitle: application.jobTitle,

      salary,
      joiningDate,
      offerDate: new Date().toISOString().split("T")[0],
      location,
      notes,

      status: "OFFER_SENT"
    };

    existingOffers.push(newOffer);
    localStorage.setItem("offerLetters", JSON.stringify(existingOffers));

    /* ---------- UPDATE APPLICATION STATUS ---------- */
    const applications =
      JSON.parse(localStorage.getItem("applications")) || [];

    const updatedApplications = applications.map((app) =>
      String(app.id) === String(applicationId)
        ? { ...app, status: "Offer Sent" }
        : app
    );

    localStorage.setItem(
      "applications",
      JSON.stringify(updatedApplications)
    );

    alert("Offer Letter Sent Successfully");
    navigate("/dashboard/view-applicants");
  };

  if (!application) return <p>Loading application...</p>;

  return (
    <div style={{ marginTop: "25px", maxWidth: "600px" }}>
      <h2>Generate Offer Letter</h2>

      <p><b>Name:</b> {application.employeeName}</p>
      <p><b>Email:</b> {application.email}</p>
      <p><b>Job Title:</b> {application.jobTitle}</p>

      <hr />

      <input
        type="number"
        placeholder="Annual Salary"
        value={salary}
        onChange={(e) => setSalary(e.target.value)}
      />
      <label>Date of Joining</label>
      <input
        type="date"
        value={joiningDate}
        onChange={(e) => setJoiningDate(e.target.value)}
      />

      <input
        type="text"
        placeholder="Work Location"
        value={location}
        onChange={(e) => setLocation(e.target.value)}
      />

      <textarea
        placeholder="Notes (optional)"
        value={notes}
        onChange={(e) => setNotes(e.target.value)}
      />

      <button
        style={{
          marginTop: "15px",
          background: "#2563eb",
          color: "white",
          padding: "10px 16px",
          borderRadius: "6px",
          border: "none",
          cursor: "pointer"
        }}
        onClick={handleSaveOffer}
      >
        Save Offer Letter
      </button>
    </div>
  );
}

export default OfferLetter;
